from flask import Flask
from flask_graphql import GraphQLView
import graphene
from graphene import ObjectType, String, Int, List, Field, Schema, Float, Boolean
from datetime import datetime

# Mock data
products_data = [
    {
        "id": 1,
        "name": "Laptop",
        "description": "High performance laptop",
        "price": 999.99,
        "category_id": 1,
        "in_stock": True,
        "created_at": "2023-01-01T00:00:00Z"
    },
    {
        "id": 2,
        "name": "Smartphone",
        "description": "Latest smartphone",
        "price": 699.99,
        "category_id": 2,
        "in_stock": True,
        "created_at": "2023-01-01T00:00:00Z"
    }
]

categories_data = [
    {"id": 1, "name": "Electronics", "description": "Electronic devices"},
    {"id": 2, "name": "Mobile", "description": "Mobile devices"}
]

reviews_data = [
    {
        "id": 1,
        "product_id": 1,
        "user_id": 1,
        "rating": 5,
        "comment": "Great laptop!",
        "created_at": "2023-01-01T00:00:00Z"
    }
]

class Review(ObjectType):
    id = Int()
    product_id = Int()
    user_id = Int()
    rating = Int()
    comment = String()
    created_at = String()

class Product(ObjectType):
    id = Int()
    name = String()
    description = String()
    price = Float()
    category_id = Int()
    in_stock = Boolean()
    created_at = String()
    reviews = List(Review)

class Category(ObjectType):
    id = Int()
    name = String()
    description = String()
    products = List(Product)

class Query(ObjectType):
    products = List(Product)
    categories = List(Category)
    product = Field(Product, id=Int(required=True))
    category = Field(Category, id=Int(required=True))
    reviews = List(Review)
    
    def resolve_products(self, info):
        return [Product(**product) for product in products_data]
    
    def resolve_categories(self, info):
        return [Category(**category) for category in categories_data]
    
    def resolve_product(self, info, id):
        product = next((p for p in products_data if p["id"] == id), None)
        return Product(**product) if product else None
    
    def resolve_category(self, info, id):
        category = next((c for c in categories_data if c["id"] == id), None)
        return Category(**category) if category else None
    
    def resolve_reviews(self, info):
        return [Review(**review) for review in reviews_data]

schema = Schema(query=Query)

app = Flask(__name__)

# Security configuration
app.config['GRAPHQL_INTROSPECTION_ENABLED'] = True
app.config['GRAPHQL_PLAYGROUND_ENABLED'] = True

# Rate limiting and query complexity
def enforce_query_limits(query):
    # Simple query depth limiting
    if query.count('{') > 10:
        raise Exception("Query too complex")
    return query

# GraphQL view with security
app.add_url_rule(
    '/graphql',
    view_func=GraphQLView.as_view(
        'graphql',
        schema=schema,
        graphiql=True,
        introspection=True,
        middleware=[],
        batch=True
    )
)

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)